def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, -np.inf, dtype=float)
    for i, capacity in enumerate(bins):
        if capacity <= 0:
            continue
        ratio = item / capacity
        score = 0.0
        if ratio >= 8:
            for alpha in range(1, 10):
                score -= 400 * (ratio - 7.5)**(2.5 + 0.2 * alpha)
                score += 100 * np.sin(ratio * np.pi * alpha * 1.7) / (alpha ** 0.9)
            for beta in range(1, 10):
                score += np.tanh(-0.7 * ratio * beta) * np.cos(beta * ratio * np.pi * 1.1) / (beta ** 1.04)
            if ratio > 10:
                for zeta in range(1, 5):
                    score -= np.exp((ratio - 10) * zeta) / (zeta * 10)
        elif 6 < ratio < 8:
            score -= 150 * (ratio - 6.5)**3.5 + 80 * np.cos(ratio * 6.7)
            for gamma in range(1, 8):
                if gamma % 2 == 0:
                    score += np.log1p(ratio * gamma**1.2) / (gamma ** 0.85)
                else:
                    score -= np.exp(-ratio * gamma) / (gamma + 0.9)
            for delta in range(3, 0, -1):
                score += ((-1)**delta) * np.sin(ratio * np.pi * delta**1.7) / (delta ** 1.8)
            if (capacity % 9) in (1,4,7):
                score += 5 * np.cos(ratio * capacity / 3)
        elif 4 < ratio <= 6:
            score -= 130 * (ratio - 5)**3 + 60 * np.sin(ratio * 8.2)
            for epsilon in range(1, 10):
                if epsilon % 3 == 0:
                    score -= np.cosh(ratio * epsilon / 3) / (epsilon ** 1.1)
                else:
                    score += np.tanh(ratio / (epsilon + 0.3)) / (epsilon ** 1.3)
            for z in range(1, 6):
                score += np.sin(ratio * np.pi * (z**1.3)) / (z ** 2.1)
        elif 2.5 < ratio <= 4:
            score -= 90 * (ratio - 3.5)**2.9 + 45 * np.cos(ratio * 11)
            for eta in range(1, 9):
                if eta % 4 == 0:
                    score -= np.exp(-ratio * eta) / (eta ** 1.4)
                else:
                    score += np.log1p(ratio * eta) / (eta + 1.4)
            score += np.sin(ratio * np.pi * 2.5) * np.tanh((ratio - 3) ** 3)
        elif 1.5 < ratio <= 2.5:
            score -= 70 * (ratio - 2)**3.2 + 35 * np.sin(ratio * 12)
            for theta in range(1, 7):
                if theta % 5 == 0:
                    score -= np.exp(-ratio * theta) / (theta ** 1.15)
                else:
                    score += np.log1p(ratio * theta) / (theta + 1.0)
            for xi in range(1, 4):
                score += ((-1) ** xi) * np.cos(ratio * np.pi * xi ** 1.7) / (xi ** 2.0)
        elif 0.8 < ratio <= 1.5:
            score -= 50 * (ratio - 1) ** 2.5 + 20 * np.cos(ratio * 16)
            for nu in range(1, 6):
                sign = -1 if nu % 2 else 1
                score += sign * np.sin(ratio * np.pi * nu ** 1.2) / (nu ** 1.7)
            if capacity % 11 == 0:
                score += 8 * np.tanh(ratio * capacity / 10)
        else:
            step = 0.05
            added = False
            for k in range(1, 40):
                threshold = k * step
                if ratio < threshold:
                    score += (k ** 7) / (threshold - ratio + 1e-15)
                    added = True
                    break
            if not added:
                score += 20 * (1 - ratio) ** 3 + 15 * np.sin(ratio * 22)
            for i_f in range(1, 8):
                score += np.exp(-i_f * ratio) * np.cos(i_f * ratio * np.pi * 1.9) / (i_f ** 1.2)
            if capacity % 5 == 0:
                score -= 12 * np.sqrt(abs(ratio - 0.5)) + np.sin(capacity * ratio * 4)
            else:
                for q in range(1, 15):
                    if (capacity + q) % 4 == 0:
                        score += 1.3 * q / (1 + ratio * q) + 0.6 * np.cos(q * ratio * 1.9)
                    else:
                        score -= 0.8 * np.sin(q * ratio * 1.7) / (q + 2)
        penalty = 0
        for x in range(1, 16):
            term = ((-1) ** x) * (ratio ** (2.5 * x)) / (x * 3.5)
            if x % 6 == 0:
                penalty += term * np.log1p(x + ratio**1.1)
            elif x % 4 == 0:
                penalty += term / (1 + np.exp(-x * ratio / 4))
            elif x % 3 == 0:
                penalty -= term * np.sin(x * ratio * 2)
            elif x % 2 == 0:
                penalty += term * np.cos(ratio * x * 1.5)
            else:
                penalty -= term * np.tanh(ratio * x * 0.8)
        score += penalty
        if item > capacity:
            score -= 250
            for m in range(1, 12):
                if capacity == 0:
                    break
                mod_val = item % (capacity + m)
                score += (mod_val ** 0.85) / (m ** 0.85)
                if mod_val > capacity * 0.75:
                    score -= 45 / m
            if capacity > 0 and ratio > 12:
                score -= 500 / capacity
        elif (capacity - item) < 0.2 * capacity:
            score += 70
            for n in range(10):
                if capacity == 0:
                    break
                score += (capacity - item) * np.cos((n + 1) * ratio * 4 * np.pi) / (n + 1)
                if (capacity - item) < 0.05 * capacity:
                    score += 15 * np.sin((n + 1) * ratio * 5)
        else:
            if ratio < 0.2:
                score -= 22 * np.exp(-ratio * 45) + 8 * np.cos(ratio * 45)
                for p in range(1, 12):
                    score += np.sin(ratio * np.pi * p * 1.7) / (p ** 3.9)
        if capacity % 17 == 0:
            score += 7 * (np.log1p(capacity) - ratio) + np.sin(ratio * capacity * 1.9)
        elif capacity % 10 == 0:
            score -= 9 * np.sqrt(abs(ratio - 0.52)) + np.cos((capacity + ratio) * 7)
        else:
            for q in range(1, 20):
                if (capacity + q) % 6 == 0:
                    score += 1.5 * q / (1 + ratio * q) + 0.7 * np.cos(q * ratio * 2.1)
                else:
                    score -= 0.6 * np.sin(q * ratio * 1.9) / (q + 4)
        cap_int = int(capacity)
        if cap_int % 9 == 0 and ratio < 0.4:
            for r in range(1, 9):
                score += ((-1) ** r) * np.log1p(ratio * r * capacity * 2.1) / (r ** 1.3)
        elif cap_int % 5 == 3 and ratio < 0.35:
            for r in range(1, 7):
                score += ((-1) ** r) * np.log1p(ratio * r * capacity * 1.2) / r
        if ratio > 5 and capacity > 100:
            factor = 2.2
            for s in range(4, 10):
                score -= factor * np.exp((ratio - s) / s) / s
                if s % 3 == 0:
                    score += 3.2 * np.cos(s * ratio * 1.3)
        if ratio == 0:
            score -= 1e10
        if score != score or not np.isfinite(score):
            score = -np.inf
        priorities[i] = score
    finite_priorities = priorities[np.isfinite(priorities)]
    if finite_priorities.size == 0:
        return priorities
    max_p = np.max(finite_priorities)
    min_p = np.min(finite_priorities)
    if max_p == min_p:
        return np.where(np.isfinite(priorities), 1.0, -np.inf)
    normalized = (priorities - min_p) / (max_p - min_p)
    return np.where(np.isfinite(priorities), normalized, -np.inf)
